public class Queue {
    private Node front;
    private Node rear;

public void enqueue(int value) {
        Node node = new Node(value);
        if (rear == null) {
            front = rear = node;
        } else {
            rear.next = node;
            rear = node;
        }
    }

public int dequeue() {
        if (front == null)
            throw new RuntimeException("Queue is empty");
        int value = front.value;
        front = front.next;
        if (front == null)
            rear = null;
        return value;
    }
